class Solution:
    def longestBalanced(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            ev = set()
            od = set()
            for j in range(i, n):
                v = nums[j]
                if v % 2 == 0:
                    ev.add(v)
                else:
                    od.add(v)
                if len(ev) == len(od):
                    best = max(best, j - i + 1)
        return best

