class Solution:
    def longestBalanced(self, nums):
        n = len(nums)
        if n == 0:
            return 0
        size = 1
        while size < n:
            size *= 2
        mn = [0] * (2 * size)
        mx = [0] * (2 * size)
        lazy = [0] * (2 * size)
        def apply(node, val):
            mn[node] += val
            mx[node] += val
            lazy[node] += val
        def update(node, l, r, ql, qr, val):
            if qr < l or r < ql:
                return
            if ql <= l and r <= qr:
                apply(node, val)
                return
            if lazy[node]:
                apply(2 * node, lazy[node])
                apply(2 * node + 1, lazy[node])
                lazy[node] = 0
            m = (l + r) // 2
            update(2 * node, l, m, ql, qr, val)
            update(2 * node + 1, m + 1, r, ql, qr, val)
            mn[node] = min(mn[2 * node], mn[2 * node + 1])
            mx[node] = max(mx[2 * node], mx[2 * node + 1])
        def query(R):
            def rec(node, l, r):
                if l > R:
                    return -1
                if mn[node] <= 0 <= mx[node]:
                    if l == r:
                        return l if mn[node] == 0 else -1
                    if lazy[node]:
                        apply(2 * node, lazy[node])
                        apply(2 * node + 1, lazy[node])
                        lazy[node] = 0
                    m = (l + r) // 2
                    left = rec(2 * node, l, m)
                    if left != -1:
                        return left
                    return rec(2 * node + 1, m + 1, r)
                return -1
            return rec(1, 0, size - 1)
        last = {}
        best = 0
        for j in range(n):
            v = nums[j]
            sgn = 1 if v % 2 == 0 else -1
            lo = last.get(v, -1) + 1
            update(1, 0, size - 1, lo, j, sgn)
            last[v] = j
            idx = query(j)
            if idx != -1:
                best = max(best, j - idx + 1)
        return best

