var longestBalanced = function(nums) {
    const n = nums.length;
    if (n === 0) return 0;
    let size = 1;
    while (size < n) size *= 2;
    const mn = new Int32Array(2 * size);
    const mx = new Int32Array(2 * size);
    const lazy = new Int32Array(2 * size);
    const apply = (node, val) => { mn[node] += val; mx[node] += val; lazy[node] += val; };
    const update = (node, l, r, ql, qr, val) => {
        if (qr < l || r < ql) return;
        if (ql <= l && r <= qr) { apply(node, val); return; }
        if (lazy[node]) { apply(2 * node, lazy[node]); apply(2 * node + 1, lazy[node]); lazy[node] = 0; }
        const m = (l + r) >> 1;
        update(2 * node, l, m, ql, qr, val);
        update(2 * node + 1, m + 1, r, ql, qr, val);
        mn[node] = Math.min(mn[2 * node], mn[2 * node + 1]);
        mx[node] = Math.max(mx[2 * node], mx[2 * node + 1]);
    };
    const query = (R) => {
        const rec = (node, l, r) => {
            if (l > R) return -1;
            if (mn[node] <= 0 && 0 <= mx[node]) {
                if (l === r) return mn[node] === 0 ? l : -1;
                if (lazy[node]) { apply(2 * node, lazy[node]); apply(2 * node + 1, lazy[node]); lazy[node] = 0; }
                const m = (l + r) >> 1;
                const left = rec(2 * node, l, m);
                if (left !== -1) return left;
                return rec(2 * node + 1, m + 1, r);
            }
            return -1;
        };
        return rec(1, 0, size - 1);
    };
    const last = new Map();
    let best = 0;
    for (let j = 0; j < n; j++) {
        const v = nums[j];
        const sgn = (v % 2 === 0) ? 1 : -1;
        const lo = (last.has(v) ? last.get(v) : -1) + 1;
        update(1, 0, size - 1, lo, j, sgn);
        last.set(v, j);
        const idx = query(j);
        if (idx !== -1) best = Math.max(best, j - idx + 1);
    }
    return best;
};
